Write-Host "Installation Auth Supabase..." -ForegroundColor Yellow

New-Item -ItemType Directory -Force -Path "apps" | Out-Null
New-Item -ItemType Directory -Force -Path "apps\web" | Out-Null
New-Item -ItemType Directory -Force -Path "apps\web\src" | Out-Null
New-Item -ItemType Directory -Force -Path "apps\web\src\app" | Out-Null
New-Item -ItemType Directory -Force -Path "apps\web\src\app\auth" | Out-Null
New-Item -ItemType Directory -Force -Path "apps\web\src\app\auth\login" | Out-Null
New-Item -ItemType Directory -Force -Path "apps\web\src\app\auth\signup" | Out-Null

[System.IO.File]::WriteAllBytes("apps\web\src\app\auth\actions.ts", [System.Convert]::FromBase64String(""))
Write-Host "  + apps/web/src/app/auth/actions.ts" -ForegroundColor DarkGray
[System.IO.File]::WriteAllBytes("apps\web\src\app\auth\login\page.tsx", [System.Convert]::FromBase64String(""))
Write-Host "  + apps/web/src/app/auth/login/page.tsx" -ForegroundColor DarkGray
[System.IO.File]::WriteAllBytes("apps\web\src\app\auth\signup\page.tsx", [System.Convert]::FromBase64String(""))
Write-Host "  + apps/web/src/app/auth/signup/page.tsx" -ForegroundColor DarkGray
[System.IO.File]::WriteAllBytes("apps\web\src\middleware.ts", [System.Convert]::FromBase64String(""))
Write-Host "  + apps/web/src/middleware.ts" -ForegroundColor DarkGray

Write-Host "Auth installée ! Relance npx next dev" -ForegroundColor Green